async function get_all_batches(container_no) {
    let all_batches = [];
    let page = 0;
    const page_size = 50;

    while (true) {
        let response = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Batch',
                filters: { custom_container_no: container_no },
                fields: [
                    'name','custom_glue','custom_pulp','custom_lusture','custom_grade','custom_lot_no','custom_fsc',
                    'custom_cone','item','item_name','manufacturing_date','cross_section','batch_qty','stock_uom','expiry_date',
                    'supplier','custom_supplier_batch_no','custom_container_no','custom_cone', 'custom_merge_no','custom_warehouse'
                ],
                limit_page_length: page_size,
                limit_start: page * page_size,
                order_by: 'name asc'
            }
        });

        let batches = response.message || [];

        if (batches.length === 0) break;

        all_batches = all_batches.concat(batches);

        if (batches.length < page_size) break;

        page++;
    }

    return all_batches;
}

// ── Shared: fetch all batches by item (custom_denier trigger) ────────────────
async function get_all_batches_by_item(item) {
    let all_batches = [];
    let page = 0;
    const page_size = 50;

    while (true) {
        let response = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Batch',
                filters: { item: item },
                fields: [
                    'name','custom_glue','custom_pulp','custom_lusture','custom_grade','custom_lot_no','custom_fsc',
                    'custom_cone','item','item_name','manufacturing_date','cross_section','batch_qty','stock_uom','expiry_date',
                    'supplier','custom_supplier_batch_no','custom_container_no','custom_cone','custom_merge_no','custom_warehouse'
                ],
                limit_page_length: page_size,
                limit_start: page * page_size,
                order_by: 'name asc'
            }
        });

        let batches = response.message || [];
        if (batches.length === 0) break;
        all_batches = all_batches.concat(batches);
        if (batches.length < page_size) break;
        page++;
    }

    return all_batches;
}

// ── Strip the "Label-" prefix for HTY display only ───────────────────────────
// e.g. "Glue-CENT" → "CENT", "Glue-PALLET" → "PALLET", "Grade-B" → "B".
// Used ONLY for the Product / Type / Colour / Grade table cells.
// Empty → "-". Values without a hyphen are returned unchanged.
function strip_label_prefix(val) {
    if (val === null || val === undefined || val === '') return '-';
    const s = String(val);
    const idx = s.indexOf('-');
    return idx >= 0 ? s.substring(idx + 1) : s;
}


function show_hty_batch_dialog(frm, batches) {
    // batch_name → batch object map for O(1) lookup in primary_action
    const batch_map = {};
    batches.forEach(b => { batch_map[b.name] = b; });

    // ── Removed columns: FSC, Cross Section, Expiry Date, Supplier, Merge No ──
    // ── Renamed (display): Glue→Product, Pulp→Type, Lusture→Colour ───────────
    // ── Prefix-stripped (display): Product, Type, Colour, Grade ──────────────
    let rows_html = batches.map(batch => `
        <tr data-batch="${batch.name}">
            <td style="text-align:center;">
                <input type="checkbox" name="batch_select_hty" value="${batch.name}">
            </td>
            <td>${batch.custom_lot_no || '-'}</td>
            <td>${batch.custom_cone || '-'}</td>
            <td>${strip_label_prefix(batch.custom_glue)}</td>
            <td>${strip_label_prefix(batch.custom_pulp)}</td>
            <td>${strip_label_prefix(batch.custom_lusture)}</td>
            <td>${strip_label_prefix(batch.custom_grade)}</td>
            <td>${batch.item || '-'}</td>
            <td>${batch.manufacturing_date || '-'}</td>
            <td>${batch.batch_qty || '-'}</td>
            <td>${batch.stock_uom || '-'}</td>
            <td>${batch.custom_supplier_batch_no || '-'}</td>
            <td>${batch.custom_container_no || '-'}</td>
            <td>${batch.custom_warehouse || '-'}</td>
        </tr>
    `).join('');

    const col_count = 14; // Select + 13 data columns
    let filter_cells = `<th></th>` + Array.from({ length: col_count - 1 }, (_, i) =>
        `<th><input type="text" data-col="${i + 1}" placeholder="Filter…"
            style="width:100%;box-sizing:border-box;font-size:11px;padding:2px 4px;border:1px solid #ccc;border-radius:3px;"></th>`
    ).join('');

    let dialog_content = `
        <div style="max-height:400px; overflow-y:auto; overflow-x:auto;">
            <table id="batch_filter_table" class="table table-bordered table-striped"
                   style="width:100%; margin-bottom:0; font-size:12px;">
                <thead>
                    <tr>
                        <th style="width:50px; text-align:center;">Select</th>
                        <th>Lot No</th><th>Cone</th><th>Product</th>
                        <th>Type</th><th>Colour</th><th>Grade</th>
                        <th>Item</th><th>Mfg Date</th><th>Batch Qty</th>
                        <th>Stock UOM</th><th>Supplier Batch No</th><th>Container No</th>
                        <th>Warehouse</th>
                    </tr>
                    <tr id="batch_filter_row">${filter_cells}</tr>
                </thead>
                <tbody id="batch_tbody">
                    ${rows_html}
                </tbody>
            </table>
        </div>
    `;

    let d = new frappe.ui.Dialog({
        title: __('Select Batch'),
        fields: [{ fieldtype: 'HTML', fieldname: 'batch_list', options: dialog_content }],
        size: 'extra-large',
        primary_action_label: __('Select'),
        primary_action: function() {
            let checked = d.wrapper.find('input[name="batch_select_hty"]:checked');

            if (checked.length === 0) {
                frappe.msgprint(__('Please select at least one batch'));
                return;
            }

            let selected_names = checked.map(function() { return $(this).val(); }).get();

            // ── Set header-level fields from the LAST selected row ────────────
            // (uses batch_map — no extra db call needed)
            const last_batch = batch_map[selected_names[selected_names.length - 1]];
            frm.set_value('custom_glue',    last_batch.custom_glue    || '');
            frm.set_value('custom_pulp',    last_batch.custom_pulp    || '');
            frm.set_value('custom_lusture', last_batch.custom_lusture || '');
            frm.set_value('custom_grade',   last_batch.custom_grade   || '');
            frm.set_value('custom_lot_no',  last_batch.custom_lot_no  || '');
            frm.set_value('custom_fsc',     last_batch.custom_fsc     || '');
            frm.set_value('custom_cone',    last_batch.custom_cone    || '');
            // MI1-I72 P3 (Raj 2026-07-10): direct doc write instead of set_value —
            // set_value would trigger the async custom_denier handler below,
            // which then opens a SECOND show_hty_batch_dialog on top of the
            // first. Direct assignment updates the value without re-firing
            // the trigger chain.
            frm.doc.custom_denier = last_batch.item || '';
            frm.refresh_field('custom_denier');

            // MI1-I72 P2 (Raj 2026-07-10): removed erroneous set_value copies for custom_product / custom_type / custom_colour — they were sourced from the batch's custom_glue / pulp / lusture, so Product prefilled with Glue's value etc.

            // ── Fetch items for ALL selected batches in parallel ──────────────
            // Each selected dialog row = one batch doc already in batch_map.
            // We call fetch_batches once per selected batch using that batch's
            // own fields as filters so the server returns exactly that batch's
            // stock entries and adds them to the items child table.
            let fetch_promises = selected_names.map(batch_name => {
                const b = batch_map[batch_name];
                return new Promise((resolve) => {
                    frappe.call({
                        method: "mhr.note.fetch_batches",
                        args: {
                            limit:        frm.doc.count || 0,
                            lot_no:       b.custom_lot_no       || '',
                            container_no: b.custom_container_no || '',
                            glue:         b.custom_glue         || '',
                            pulp:         b.custom_pulp         || '',
                            fsc:          b.custom_fsc          || '',
                            lusture:      b.custom_lusture      || '',
                            grade:        b.custom_grade        || '',
                            cone:         b.custom_cone         || '',
                            denier:       b.item                || '',
                        },
                        callback: function(response) {
                            resolve(response.message || []);
                        }
                    });
                });
            });

            Promise.all(fetch_promises).then(results => {
                // results = [[batches for row1], [batches for row4], [batches for row5], ...]
                let added_count   = 0;
                let skipped_count = 0;

                // results.forEach(batches_for_row => {
                //     batches_for_row.forEach(function(data) {
                //         // Skip if batch already exists in items table
                //         var exists = frm.doc.items.some(function(row) {
                //             return row.batch_no === data.name;
                //         });

                //         if (!exists) {
                //             frm.add_child("items", {
                //                 item_code:                  data.item,
                //                 item_name:                  data.item_name,
                //                 qty:                        data.batch_qty,
                //                 batch_no:                   data.name,
                //                 uom:                        data.stock_uom,
                //                 custom_cone:                data.custom_cone,
                //                 custom_supplier_batch_no:   data.custom_supplier_batch_no,
                //                 custom_container_no:        data.custom_container_no,
                //                 custom_lot_no:              data.custom_lot_no,
                //                 use_serial_batch_fields:    1
                //             });
                //             added_count++;
                //             if (data.custom_notes && !frm.doc.custom_notes) {
                //                 frm.set_value("custom_notes", data.custom_notes);
                //             }
                //         } else {
                //             skipped_count++;
                //         }
                //     });
                // });

                // frm.refresh_field("items");
                // frm.set_value("custom_supplier_batch_no", "");
                // calculate_totals(frm);

                // d.hide();
                
                selected_names.forEach(batch_name => {
                const data = batch_map[batch_name];
                if (!data) return;

                // Skip if this exact batch is already in items
                const exists = frm.doc.items.some(row => row.batch_no === data.name);
                if (exists) {
                    skipped_count++;
                    return;
                }

                frm.add_child("items", {
                        item_code:                data.item,
                        item_name:                data.item_name,
                        qty:                      data.batch_qty,
                        batch_no:                 data.name,
                        uom:                      data.stock_uom,
                        custom_cone:              data.custom_cone,
                        custom_supplier_batch_no: data.custom_supplier_batch_no,
                        custom_container_no:      data.custom_container_no,
                        custom_lot_no:            data.custom_lot_no,
                        use_serial_batch_fields:  1
                    });
                    added_count++;
                });
    
                // MI1-I75 (Raj 2026-06-29): sort by Supplier Batch No ascending — HTY only.
                if (String(frm.doc.transaction_type || '').toUpperCase() === 'HTY') {
                    frm.doc.items.sort((a, b) =>
                        String(a.custom_supplier_batch_no || '').localeCompare(
                            String(b.custom_supplier_batch_no || ''),
                            undefined, { numeric: true, sensitivity: 'base' }
                        )
                    );
                    frm.doc.items.forEach((row, k) => { row.idx = k + 1; });
                }
                frm.refresh_field("items");
                frm.set_value("custom_supplier_batch_no", "");
                calculate_totals(frm);
    
                d.hide();
            
            });
        }
    });

    d.show();

    // Live column filters
    d.wrapper.on('input', '#batch_filter_row input', function() {
        let filters = [];
        d.wrapper.find('#batch_filter_row input').each(function() {
            let val = $(this).val().trim().toLowerCase();
            if (val) filters.push({ col: parseInt($(this).data('col')), val });
        });

        d.wrapper.find('#batch_tbody tr').each(function() {
            let row = $(this);
            let visible = filters.every(f => {
                let cell_text = row.find('td').eq(f.col).text().toLowerCase();
                return cell_text.includes(f.val);
            });
            row.toggle(visible);
        });
    });
}

