// ── VFY: fetch batches with only the 2 fields needed ─────────────────────────
async function get_all_batches_vfy(container_no) {
    let all_batches = [];
    let page = 0;
    const page_size = 50;

    while (true) {
        let response = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Batch',
                filters: { custom_container_no: container_no },
                fields: ['name', 'custom_lot_no', 'custom_cone'],
                limit_page_length: page_size,
                limit_start: page * page_size,
                order_by: 'name asc'
            }
        });

        let batches = response.message || [];
        if (batches.length === 0) break;
        all_batches = all_batches.concat(batches);
        if (batches.length < page_size) break;
        page++;
    }

    return all_batches;
}

frappe.ui.form.on('Delivery Note', {

    // ── Trigger 1: custom_container_no ───────────────────────────────────────
    async custom_container_no(frm) {
        if (!frm.doc.custom_container_no) {
            clear_batch_fields(frm);
            return;
        }

        // VFY — original behaviour: 2 columns, single select
        if (frm.doc.transaction_type === "VFY") {
            let batches = await get_all_batches_vfy(frm.doc.custom_container_no);

            if (batches.length === 0) {
                frappe.msgprint(__('No Batch found with Container No: {0}', [frm.doc.custom_container_no]));
                clear_batch_fields(frm);
                return;
            }

            let rows_html = batches.map(batch => `
                <tr>
                    <td style="text-align:center;">
                        <input type="radio" name="batch_select_vfy" value="${batch.name}">
                    </td>
                    <td>${batch.custom_lot_no || '-'}</td>
                    <td>${batch.custom_cone || '-'}</td>
                </tr>
            `).join('');

            let dialog_content = `
                <div style="max-height:300px; overflow-y:auto;">
                    <table class="table table-bordered table-striped" style="width:100%; margin-bottom:0;">
                        <thead>
                            <tr>
                                <th style="width:50px; text-align:center;">Select</th>
                                <th>Lot No</th>
                                <th>Cone</th>
                            </tr>
                        </thead>
                        <tbody>${rows_html}</tbody>
                    </table>
                </div>
            `;

            let d = new frappe.ui.Dialog({
                title: __('Select Batch'),
                fields: [{ fieldtype: 'HTML', fieldname: 'batch_list', options: dialog_content }],
                size: 'large',
                primary_action_label: __('Select'),
                primary_action: function() {
                    let selected_batch_name = d.wrapper.find('input[name="batch_select_vfy"]:checked').val();

                    if (!selected_batch_name) {
                        frappe.msgprint(__('Please select a batch'));
                        return;
                    }

                    frappe.db.get_doc('Batch', selected_batch_name).then(batch => {
                        frm.set_value('custom_glue',    batch.custom_glue    || '');
                        frm.set_value('custom_pulp',    batch.custom_pulp    || '');
                        frm.set_value('custom_lusture', batch.custom_lusture || '');
                        frm.set_value('custom_grade',   batch.custom_grade   || '');
                        frm.set_value('custom_lot_no',  batch.custom_lot_no  || '');
                        frm.set_value('custom_fsc',     batch.custom_fsc     || '');
                        frm.set_value('custom_cone',    batch.custom_cone    || '');
                        frm.set_value('custom_denier',  batch.item           || '');
                        d.hide();
                    });
                }
            });

            d.show();
            return;
        }

        // HTY — new behaviour: full columns, checkboxes, filters
        if (frm.doc.transaction_type === "HTY") {
            let batches = await get_all_batches(frm.doc.custom_container_no);

            if (batches.length === 0) {
                frappe.msgprint(__('No Batch found with Container No: {0}', [frm.doc.custom_container_no]));
                clear_batch_fields(frm);
                return;
            }

            show_hty_batch_dialog(frm, batches);
            return;
        }

        clear_batch_fields(frm);
    },

    // ── Trigger 2: custom_denier — HTY only, filter by item ──────────────────
    async custom_denier(frm) {
        if (!frm.doc.custom_denier) {
            clear_batch_fields(frm);
            return;
        }

        if (frm.doc.transaction_type !== "HTY") {
            return;
        }

        let batches = await get_all_batches_by_item(frm.doc.custom_denier);

        if (batches.length === 0) {
            frappe.msgprint(__('No Batch found with Item: {0}', [frm.doc.custom_denier]));
            clear_batch_fields(frm);
            return;
        }

        show_hty_batch_dialog(frm, batches);
    }

});

