async function get_batches_for_lot_cone_dialog(container_no) {
    let all_batches = [];
    let page = 0;
    const page_size = 50;

    while (true) {
        let response = await frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Batch',
                filters: { custom_container_no: container_no },
                fields: [
                    'name',
                    'custom_glue',
                    'custom_pulp',
                    'custom_lusture',
                    'custom_grade',
                    'custom_lot_no',
                    'custom_fsc',
                    'custom_cone',
                    'item'
                ],
                limit_page_length: page_size,
                limit_start: page * page_size,
                order_by: 'name asc'
            }
        });

        let batches = response.message || [];

        if (batches.length === 0) break;

        all_batches = all_batches.concat(batches);

        if (batches.length < page_size) break;

        page++;
    }

    return all_batches;
}

frappe.ui.form.on('Delivery Note', {
    async custom_container_no(frm) {
        // MI1 (Raj 2026-07-10): the Lot/Cone chooser popup below is
        // VFY-only. In HTY mode container-level fields (Colour / Type /
        // Product / Grade) live on the Container form, not on Batch,
        // and the "Pick Containers by Lot" flow (MI1-I39) is the
        // intended entry point. Skip the popup entirely for HTY.
        if ((frm.doc.transaction_type || '').toUpperCase() === 'HTY') return;
        if (frm.doc.custom_container_no) {
            let batches = await get_batches_for_lot_cone_dialog(frm.doc.custom_container_no);

            if (batches.length === 0) {
                frappe.msgprint(__('No Batch found with Container No: {0}', [frm.doc.custom_container_no]));
                clear_batch_fields(frm);
