frappe.ui.form.on('Delivery Note', {
    refresh: function(frm) {
        // Disconnect old observer if present
        if (frm.__email_modal_observer) {
            frm.__email_modal_observer.disconnect();
        }

        const observer = new MutationObserver(() => {
            const modalTitle = document.querySelector('.modal-dialog .modal-title');
            if (modalTitle && modalTitle.textContent.trim() === 'New Email') {
                // Set Recipients
                const toInput = document.querySelector('input[data-fieldname="recipients"]');
                if (toInput) {
                    toInput.value = 'billing@meherinternational.in';
                    toInput.dispatchEvent(new Event('input', { bubbles: true }));
                }

                // Set CC
                const ccInput = document.querySelector('input[data-fieldname="cc"]');
                if (ccInput) {
                    ccInput.value = 'viscose@meherinternational.in, haresh@meherinternational.in, warehouse2@meherinternational.in';
                    ccInput.dispatchEvent(new Event('input', { bubbles: true }));
                }

                // Done, disconnect observer
                frm.__email_modal_observer.disconnect();
                frm.__email_modal_observer = null;
            }
        });

        // Start watching for the email dialog
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });

        frm.__email_modal_observer = observer;
    }
});

