// Monkey-patch only once to avoid breaking other dialogs
if (!frappe.__custom_email_patch_applied) {
    const OriginalComposer = frappe.views.CommunicationComposer;

    frappe.views.CommunicationComposer = class CustomComposer extends OriginalComposer {
        make() {
            super.make();

            // Apply default recipients only for Delivery Note in List View
            const route = frappe.get_route();
            const is_delivery_note_list =
                route[0] === "List" && route[1] === "Delivery Note";

            if (is_delivery_note_list && this.dialog && this.dialog.fields_dict) {
                const recipientsField = this.dialog.fields_dict.recipients;
                const ccField = this.dialog.fields_dict.cc;
                const subjectField = this.dialog.fields_dict.subject;

                // Slight delay to ensure fields are ready
                setTimeout(() => {
                    // Get selected delivery note IDs from the list view
                    const listView = frappe.container.page.list_view;
                    const selectedDocs = listView && listView.get_checked_items ? listView.get_checked_items() : [];

                    const deliveryNoteIDs = selectedDocs.map(doc => doc.name).join(", ");

                    if (recipientsField?.set_value) {
                        recipientsField.set_value("billing@meherinternational.in");
                    }
                    if (ccField?.set_value) {
                        ccField.set_value("viscose@meherinternational.in, haresh@meherinternational.in, warehouse2@meherinternational.in");
                    }
                    if (subjectField?.set_value) {
                        const subject = deliveryNoteIDs ? `Delivery Notes: ${deliveryNoteIDs}` : "Delivery Notes";
                        subjectField.set_value(subject);
                    }
                }, 300);
            }
        }
    };

    frappe.__custom_email_patch_applied = true;
}

