/* ====================================================================
   FETCH BATCH QTY FROM DATABASE AND CALCULATE (LIVE CHANGE)
==================================================================== */
function calculate_qty_from_database(cdn, row) {
    if (!row || !row.batch_no) return;

    // Skip if manually edited
    if (row.custom_qty_manual_edit) return;

    frappe.call({
        method: "frappe.client.get_value",
        args: {
            doctype: "Batch",
            filters: { name: row.batch_no },
            fieldname: "batch_qty"
        },
        callback: function (r) {
            if (row.custom_qty_manual_edit) return;

            if (r.message && r.message.batch_qty) {
                let database_qty = parseFloat(r.message.batch_qty);
                let cone = parseFloat(row.custom_cone);
                let cone_copy = parseFloat(row.custom_cone_copy);

                if (
                    isNaN(database_qty) ||
                    isNaN(cone) ||
                    isNaN(cone_copy) ||
                    cone_copy === 0
                ) {
                    return;
                }

                let new_qty = (database_qty * cone) / cone_copy;

                frappe.model.set_value(
                    "Delivery Note Item",
                    cdn,
                    "qty",
                    flt(new_qty, 3)
                );
            }
        }
    });
}


/* ====================================================================
   FETCH BATCH QTY AND CALCULATE (BEFORE SAVE)
==================================================================== */
function fetch_batch_qty_and_calculate(cdn, row) {
    return new Promise(resolve => {
        if (!row || !row.batch_no) {
            resolve();
            return;
        }

        // Skip if manually edited
        if (row.custom_qty_manual_edit) {
            resolve();
            return;
        }

        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Batch",
                filters: { name: row.batch_no },
                fieldname: "batch_qty"
            },
            callback: function (r) {
                if (row.custom_qty_manual_edit) {
                    resolve();
                    return;
                }

                if (r.message && r.message.batch_qty) {
                    let database_qty = parseFloat(r.message.batch_qty);
                    let cone = parseFloat(row.custom_cone);
                    let cone_copy = parseFloat(row.custom_cone_copy);

                    if (
                        !isNaN(database_qty) &&
                        !isNaN(cone) &&
                        !isNaN(cone_copy) &&
                        cone_copy !== 0
                    ) {
                        let new_qty = (database_qty * cone) / cone_copy;

                        frappe.model.set_value(
                            "Delivery Note Item",
                            cdn,
                            "qty",
                            flt(new_qty, 3)
                        );
                    }
                }
                resolve();
            },
            error: function () {
                resolve();
            }
        });
    });
}

