function fetch_and_fill_batches(frm) {
    let item_code = frm.doc.custom_daniar;
    let container_no = frm.doc.custom_container_no;
    let lot_no = frm.doc.custom_lot_no;
    let qty = frm.doc.custom_quantity_weight || 0;

    if (\!item_code) return;

    frappe.call({
        method: 'mhr.utilis.get_so_batches',
        args: {
            item_code: item_code,
            container_no: container_no,
            lot_no: lot_no,
            qty: qty
        },
        callback: function(r) {
            if (\!r.message || \!r.message.length) {
                frappe.msgprint(__('No batches found with available stock for the given filters.'));
                return;
            }

            frm.clear_table('items');

            let batches = r.message;
            let total_qty = 0;

            batches.forEach(function(batch) {
                let row = frm.add_child('items');
                frappe.model.set_value(row.doctype, row.name, 'item_code', batch.item);
                frappe.model.set_value(row.doctype, row.name, 'qty', batch.allotted_qty);
                frappe.model.set_value(row.doctype, row.name, 'custom_batch_no', batch.name);
                frappe.model.set_value(row.doctype, row.name, 'custom_lot_number', batch.custom_lot_no);
                frappe.model.set_value(row.doctype, row.name, 'custom_container_number', batch.custom_container_no);
                frappe.model.set_value(row.doctype, row.name, 'custom_grade', batch.custom_grade);
                total_qty += batch.allotted_qty;
            });

            frm.refresh_field('items');

            if (qty && total_qty < qty) {
                frappe.msgprint(
                    __('Only {0} available across {1} batch(es). Requested: {2}',
                    [total_qty, batches.length, qty])
                );
            }
        }
    });
}

