                frappe.model.set_value(cdt, cdn, 'item_code', d.item_code);
                frappe.model.set_value(cdt, cdn, 'custom_lot_number', d.lot_no);
                frappe.model.set_value(cdt, cdn, 'custom_container_number', d.container_no);
                frappe.model.set_value(cdt, cdn, 'custom_grade', d.grade);
            }
        });
    }
});

frappe.ui.form.on('Stock Entry', {
    refresh(frm) {
        calculate_totals(frm);
        frm.set_query('custom_container_number', function() {
            return { filters: { docstatus: ['!=', 2] } };
        });
    },

    before_save: function(frm) {
        (frm.doc.items || []).forEach(function(row) {
            if (!row.conversion_factor || row.conversion_factor === 0) {
                row.conversion_factor = 1;
            }
            row.transfer_qty = flt(row.qty) * flt(row.conversion_factor);
        });
    },

    custom_container_number: function(frm) {
        if (frm.doc.custom_container_number) {
            get_container_no(frm, function(container_no) {
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Batch',
                        filters: { custom_container_no: container_no },
                        fields: ['name', 'custom_glue', 'custom_pulp', 'custom_lusture', 'custom_grade', 'custom_lot_no', 'custom_fsc', 'custom_cone', 'item', 'custom_container_no'],
                        limit_page_length: 100,
                        order_by: 'name asc'
                    },
                    callback: function(r) {
                        let batches = r.message || [];
                        if (batches.length === 0) {
                            frappe.msgprint(__('No Batch found with Container No: {0}', [container_no]));
                            clear_batch_fields_se(frm);
                            return;
                        }

                        let rows_html = batches.map(batch => `
                            <tr>
                                <td style="text-align:center;"><input type="radio" name="batch_select" value="${batch.name}"></td>
                                <td>${batch.custom_lot_no || '-'}</td>
                                <td>${batch.custom_cone != null ? batch.custom_cone : '-'}</td>
                            </tr>
                        `).join('');

                        let d = new frappe.ui.Dialog({
                            title: __('Select Batch'),
                            fields: [{
                                fieldtype: 'HTML',
                                fieldname: 'batch_list',
                                options: `<div style="max-height:300px;overflow-y:auto;"><table class="table table-bordered table-striped" style="width:100%;margin-bottom:0;"><thead><tr><th style="width:50px;text-align:center;">Select</th><th>Lot No</th><th>Cone</th></tr></thead><tbody>${rows_html}</tbody></table></div>`
                            }],
                            primary_action_label: __('Select'),
                            primary_action: function() {
                                let selected = d.wrapper.find('input[name="batch_select"]:checked').val();
                                if (!selected) {
                                    frappe.msgprint(__('Please select a batch'));
                                    return;
                                }
                                frappe.db.get_doc('Batch', selected).then(batch => {
                                    frm.set_value('custom_glue', batch.custom_glue || '');
                                    frm.set_value('custom_pulp', batch.custom_pulp || '');
                                    frm.set_value('custom_lusture', batch.custom_lusture || '');
                                    frm.set_value('custom_grade', batch.custom_grade || '');
                                    frm.set_value('custom_lot_no', batch.custom_lot_no || '');
                                    frm.set_value('custom_fsc', batch.custom_fsc || '');
                                    frm.set_value('custom_se_cone', batch.custom_cone != null ? batch.custom_cone : 0);
                                    frm.set_value('custom_denier', batch.item || '');
                                    d.hide();
                                });
                            }
                        });
                        d.show();
                    }
                });
            });
        } else {
            clear_batch_fields_se(frm);
        }
    },

    custom_supplier_batch_no: function(frm) {
        fetch_and_append_batch_se(frm);
    },

    custom_scan_batch_no: function(frm) {
        if (!frm.doc.custom_scan_batch_no) return;

        const existingRow = frm.doc.items.find(d => d.batch_no === frm.doc.custom_scan_batch_no);
        if (existingRow) {
            frappe.msgprint(__('Batch already exists in the table'));
            frm.set_value('custom_scan_batch_no', '');
            return;
        }

        frappe.call({
            method: 'mhr.utilis.get_item_batch',
            args: { batch: frm.doc.custom_scan_batch_no },
            callback: function(r) {
                if (!r.message || r.message.error) return;
                let safe = (v) => (v || '').toString().trim().toLowerCase();
                let d = r.message;

                if (safe(d.glue) !== safe(frm.doc.custom_glue) ||
                    safe(d.lusture) !== safe(frm.doc.custom_lusture) ||
                    safe(d.grade) !== safe(frm.doc.custom_grade) ||
                    safe(d.pulp) !== safe(frm.doc.custom_pulp) ||
                    safe(d.fsc) !== safe(frm.doc.custom_fsc)) {
                    frappe.msgprint(__('Parameters are not the same as the value in batch'));
                    frm.set_value('custom_scan_batch_no', '');
                    return;
                }

                if (frm.doc.custom_se_cone && cint(d.cone) !== cint(frm.doc.custom_se_cone)) {
                    frappe.msgprint(__('Parameters are not the same as the value in batch'));
                    frm.set_value('custom_scan_batch_no', '');
                    return;
                }

                frm.add_child('items', {
                    item_code: d.item_code,
                    qty: d.qty,
                    conversion_factor: 1,
                    transfer_qty: flt(d.qty),
                    batch_no: d.batch_no,
                    uom: d.uom,
                    custom_cone: d.cone,
                    use_serial_batch_fields: 1
                });
                frm.doc.items.unshift(frm.doc.items.pop());
                frm.refresh_field('items');
                frm.set_value('custom_scan_batch_no', '');
                if (d.notes) {
                    frm.set_value('custom_notes', d.notes);
                }
                calculate_totals(frm);
            }
        });
    },

    custom_fetch_batches: function(frm) {
        if (!frm.doc.custom_fetch_batches) return;
        get_container_no(frm, function(container_no) {
            frappe.call({
                method: 'mhr.note.fetch_batches',
                args: {
                    limit: frm.doc.custom_count || 50,
                    lot_no: frm.doc.custom_lot_no,
                    container_no: container_no,
                    glue: frm.doc.custom_glue,
                    pulp: frm.doc.custom_pulp,
                    fsc: frm.doc.custom_fsc,
                    lusture: frm.doc.custom_lusture,
                    grade: frm.doc.custom_grade,
                    cone: frm.doc.custom_se_cone,
                    denier: frm.doc.custom_denier
                },
                callback: function(response) {
                    if (response.message && response.message.length > 0) {
                        let batches = response.message;
                        frm.doc.items = (frm.doc.items || []).filter(row => row.item_code);
                        batches.forEach(function(data) {
                            let exists = frm.doc.items.some(row => row.batch_no === data.name);
                            if (!exists) {
                                frm.add_child('items', {
                                    item_code: data.item,
                                    qty: data.batch_qty,
                                    conversion_factor: 1,
                                    transfer_qty: flt(data.batch_qty),
                                    batch_no: data.name,
                                    uom: data.stock_uom,
                                    custom_cone: data.custom_cone,
                                    use_serial_batch_fields: 1
                                });
                                if (data.custom_notes && !frm.doc.custom_notes) {
                                    frm.set_value('custom_notes', data.custom_notes);
                                }
                            }
                        });
                        frm.refresh_field('items');
                        calculate_totals(frm);
                    } else {
                        frappe.msgprint(__('No batches found matching the criteria.'));
                    }
                    frm.set_value('custom_fetch_batches', 0);
                }
            });
        });
    }
});

frappe.ui.form.on('Stock Entry Detail', {
    items_add: function(frm) { calculate_totals(frm); },
    items_remove: function(frm) { calculate_totals(frm); },
    qty: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        let cf = row.conversion_factor || 1;
        frappe.model.set_value(cdt, cdn, 'transfer_qty', flt(row.qty) * flt(cf));
        calculate_totals(frm);
    },
    conversion_factor: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        frappe.model.set_value(cdt, cdn, 'transfer_qty', flt(row.qty) * flt(row.conversion_factor || 1));
    },
    custom_cone: function(frm) { calculate_totals(frm); }
});

function calculate_totals(frm) {
    let total_cone = 0;
    let total_qty = 0;
    (frm.doc.items || []).forEach(function(row) {
        total_cone += parseFloat(row.custom_cone || 0);
        total_qty += parseFloat(row.qty || 0);
    });
    if (frm.doc.custom_total_cone !== total_cone) {
        frm.doc.custom_total_cone = total_cone;
        frm.refresh_field('custom_total_cone');
    }
    if (String(frm.doc.custom_total_qty) !== String(total_qty)) {
        frm.doc.custom_total_qty = String(total_qty);
        frm.refresh_field('custom_total_qty');
    }
}

function get_container_no(frm, callback) {
    if (!frm.doc.custom_container_number) { callback(null); return; }
    frappe.db.get_value('Container', frm.doc.custom_container_number, 'container_no', function(r) {
        callback(r && r.container_no ? r.container_no : frm.doc.custom_container_number);
    });
}

function fetch_and_append_batch_se(frm) {
    if (!frm.doc.custom_supplier_batch_no || !frm.doc.custom_container_number || !frm.doc.custom_lot_no) return;
    get_container_no(frm, function(container_no) {
        frappe.call({
            method: 'mhr.utilis.get_delivery_note_batch',
            args: {
                lot_no: frm.doc.custom_lot_no,
                container_no: container_no,
                supplier_batch_no: frm.doc.custom_supplier_batch_no,
                glue: frm.doc.custom_glue,
                pulp: frm.doc.custom_pulp,
                fsc: frm.doc.custom_fsc,
                lusture: frm.doc.custom_lusture,
                grade: frm.doc.custom_grade,
                cone: frm.doc.custom_se_cone,
                denier: frm.doc.custom_denier
            },
            callback: function(response) {
                if (!response.message) return;
                let data = response.message;
                let exists = frm.doc.items.some(row => row.batch_no === data.batch_no);
                if (exists) {
                    frappe.msgprint(__('Batch already exists in the list.'));
                    return;
                }
                frm.add_child('items', {
                    item_code: data.item_code,
                    qty: data.qty,
                    conversion_factor: 1,
                    transfer_qty: flt(data.qty),
                    batch_no: data.batch_no,
                    uom: data.uom,
                    custom_cone: data.cone,
                    use_serial_batch_fields: 1
                });
                frm.doc.items.unshift(frm.doc.items.pop());
                frm.refresh_field('items');
                frm.set_value('custom_supplier_batch_no', '');
                if (data.notes) {
                    frm.set_value('custom_notes', data.notes);
                }
                calculate_totals(frm);
            }
        });
    });
}

function clear_batch_fields_se(frm) {
    ['custom_glue', 'custom_pulp', 'custom_lusture', 'custom_grade', 'custom_lot_no', 'custom_fsc', 'custom_denier', 'custom_se_cone'].forEach(field => frm.set_value(field, ''));
}

// MI1-I39 — HTY mode toggle for Container.
// HTY: relabel Lusture→Colour, Glue→Product, Pulp→Type; hide FSC/Merge No/
// Cross Section/Production Date; show Gross Weight + Sr.No. on batch rows.
// VFY: restore original labels and visibility (starter ERPNext flow).

function mi1_i39_apply_container_hty(frm) {
    const hty = frm.doc.transaction_type === 'HTY';
    const relabel = {
        'lusture':       hty ? 'Colour'   : 'Lusture',
        'glue':          hty ? 'Product'  : 'Glue',
        'pulp':          hty ? 'Type'     : 'Pulp',
    };
    for (const [f, lbl] of Object.entries(relabel)) {
        if (frm.fields_dict[f]) frm.set_df_property(f, 'label', lbl);
    }
    const hide_in_hty = ['fsc', 'merge_no', 'cross_section', 'production_date'];
    for (const f of hide_in_hty) {
        if (frm.fields_dict[f]) frm.set_df_property(f, 'hidden', hty ? 1 : 0);
    }
    // Toggle Gross Weight + Sr.No. visibility on the Batch Items child grid.
    const grid = frm.fields_dict.batches && frm.fields_dict.batches.grid;
    if (grid) {
        ['custom_gross_weight', 'custom_sr_no'].forEach(f => {
            const df = grid.get_docfield(f);
            if (df) {
                df.hidden = hty ? 0 : 1;
                df.in_list_view = hty ? 1 : 0;
            }
        });
        // Rename Batch Quantity → Net Weight in HTY mode.
        const qty_df = grid.get_docfield('qty');
        if (qty_df) qty_df.label = hty ? 'Net Weight' : 'Batch Quantity';
        grid.refresh();
    }
}

frappe.ui.form.on('Container', {
    refresh: mi1_i39_apply_container_hty,
    transaction_type: mi1_i39_apply_container_hty,
});

// MI1-I39 — Sales Order HTY mode.
// Phase 1: label-swap for the renamed Meher fields.
// Phase 2B: company-aware filters per FRD §SO 8 rules.
//   - Warehouses (header + item rows) filter by selected Company.
//   - On Company change → auto-fetch default Price List + Cost Center.
//   - All gated by transaction_type == 'HTY'; VFY mode is untouched.
//   - Series rule is still TODO (waiting on the prefix from Nainsi).

function mi1_i39_apply_so_hty(frm) {
    const hty = frm.doc.transaction_type === 'HTY';

    // Label swap for Meher-custom fields.
    const relabel = {
        'custom_lusture': hty ? 'Colour'  : 'Lusture',
        'custom_glue':    hty ? 'Product' : 'Glue',
        'custom_pulp':    hty ? 'Type'    : 'Pulp',
    };
    for (const [f, lbl] of Object.entries(relabel)) {
        if (frm.fields_dict[f]) frm.set_df_property(f, 'label', lbl);
    }

    // P2-B: company-aware warehouse filter on header.
    // Only attach in HTY mode; VFY keeps standard ERPNext behavior.
    if (hty) {
        frm.set_query('set_warehouse', () => ({
            filters: { company: frm.doc.company || '' },
        }));
        // P2-B: same filter on each item-row warehouse picker.
        frm.set_query('warehouse', 'items', () => ({
            filters: { company: frm.doc.company || '' },
        }));
    }
}

// P2-B: when company changes in HTY mode, fetch Company defaults
// (default_price_list + cost_center) and apply them to the SO.
// Per FRD: "New company price list must auto-fetch based on company
// selection" + "New company cost center must auto-populate from
// Company master".
function mi1_i39_fetch_company_defaults(frm) {
    if (frm.doc.transaction_type !== 'HTY' || !frm.doc.company) return;
    frappe.db.get_value('Company', frm.doc.company,
        ['default_price_list', 'cost_center']
    ).then(r => {
        const v = r && r.message;
        if (!v) return;
        if (v.default_price_list && !frm.doc.selling_price_list) {
            frm.set_value('selling_price_list', v.default_price_list);
        }
        if (v.cost_center && !frm.doc.cost_center) {
            frm.set_value('cost_center', v.cost_center);
        }
    });
}

frappe.ui.form.on('Sales Order', {
    refresh: mi1_i39_apply_so_hty,
    transaction_type: function (frm) {
        mi1_i39_apply_so_hty(frm);
        mi1_i39_fetch_company_defaults(frm);
    },
    company: function (frm) {
        mi1_i39_apply_so_hty(frm);    // re-wire set_query with the new company
        mi1_i39_fetch_company_defaults(frm);
    },
});

// MI1-I39 P2-F: auto-switch naming_series when transaction_type changes.
// HTY-mode docs use the HTY-SALES-prefixed naming series.
function mi1_i39_apply_so_naming_series(frm) {
    if (frm.doc.docstatus !== 0) return;  // never change after submit
    const ns_df = frm.fields_dict.naming_series && frm.fields_dict.naming_series.df;
    if (!ns_df || !ns_df.options) return;
    const opts = (ns_df.options || '').split('\n').filter(Boolean);
    const hty_opts = opts.filter(o => o.startsWith('HTY-'));
    const non_hty_opts = opts.filter(o => !o.startsWith('HTY-'));
    if (frm.doc.transaction_type === 'HTY' && hty_opts.length) {
        // Prefer the first HTY option; only override if the user hasn't
        // picked an HTY series already.
        if (!String(frm.doc.naming_series || '').startsWith('HTY-')) {
            frm.set_value('naming_series', hty_opts[0]);
        }
    } else if (frm.doc.transaction_type !== 'HTY' && non_hty_opts.length) {
        // Flipping back to VFY: if naming_series is HTY-prefixed, swap
        // to the first non-HTY option.
        if (String(frm.doc.naming_series || '').startsWith('HTY-')) {
            frm.set_value('naming_series', non_hty_opts[0]);
        }
    }
}
frappe.ui.form.on('Sales Order', {
    refresh: mi1_i39_apply_so_naming_series,
    transaction_type: mi1_i39_apply_so_naming_series,
});

// MI1-I39 — HTY mode for Delivery Note: label swap + 4-step lot picker.

function mi1_i39_apply_dn_hty(frm) {
    const hty = frm.doc.transaction_type === 'HTY';
    // MI1-I72 (Raj 2026-07-10): the original approach relabeled the
    // three VFY-only fields (custom_lusture/glue/pulp) to
    // "Colour"/"Product"/"Type" in HTY. That's now superseded — Raj
    // added NEW parallel fields (custom_colour/custom_product/
    // custom_type) with those labels natively, and in HTY the form
    // was showing BOTH sets, giving users two "Colour" / "Product" /
    // "Type" fields side-by-side. Hide the original three entirely
    // in HTY; the new fields ARE the HTY-visible ones going forward.
    const hide_in_hty = [
        'custom_fsc',
        'custom_merge_no',
        'custom_cross_section',
        'custom_production_date',
        'custom_lusture',
        'custom_glue',
        'custom_pulp',
    ];
    for (const f of hide_in_hty) {
        if (frm.fields_dict[f]) frm.set_df_property(f, 'hidden', hty ? 1 : 0);
    }
    const grid = frm.fields_dict.items && frm.fields_dict.items.grid;
    if (grid) {
        ['custom_gross_weight','custom_sr_no'].forEach(f => {
            const df = grid.get_docfield(f);
            if (df) {
                df.hidden = hty ? 0 : 1;
                df.in_list_view = hty ? 1 : 0;
            }
        });
        grid.refresh();
    }
    mi1_i39_add_pick_by_lot_button(frm, hty);
}

// FRD §Delivery Note 4-STEP LOT-BASED WORKFLOW:
//   Step 1 — User selects Lot No (mandatory entry point)
//   Step 2 — System auto-displays Containers for that lot
//   Step 3 — User multi-selects required Containers
//   Step 4 — Proceed → carry only selected forward into DN items
function mi1_i39_add_pick_by_lot_button(frm, hty) {
    // Remove any prior instance so we don't double-add on every refresh.
    frm.remove_custom_button(__('Pick Containers by Lot'), __('HTY'));
    if (!hty || frm.doc.docstatus !== 0) return;

    frm.add_custom_button(__('Pick Containers by Lot'), function () {
        mi1_i39_open_lot_picker(frm);
    }, __('HTY'));
}

function mi1_i39_open_lot_picker(frm) {
    const d = new frappe.ui.Dialog({
        title: __('HTY — Pick Containers by Lot (4-step)'),
        size: 'large',
        fields: [
            {
                fieldname: 'step1_section',
                fieldtype: 'Section Break',
                label: __('Step 1 — Select Lot No'),
            },
            {
                fieldname: 'lot_no',
                fieldtype: 'Autocomplete',
                label: __('Lot No'),
                reqd: 1,
                description: __('Mandatory entry point. Containers appear after a lot is picked.'),
            },
            {
                fieldname: 'step2_section',
                fieldtype: 'Section Break',
                label: __('Step 2 / 3 — Containers (multi-select)'),
            },
            {
                fieldname: 'containers_html',
                fieldtype: 'HTML',
                options: '<p class="text-muted">' + __('Select a Lot No above to load containers.') + '</p>',
            },
        ],
        primary_action_label: __('Proceed'),
        primary_action: function () {
            mi1_i39_proceed(frm, d);
        },
    });

    // Populate the Lot autocomplete from server.
    frappe.call({
        method: 'mhr.utilis.get_hty_lots',
        args: { company: frm.doc.company || null },
        callback: function (r) {
            const lots = (r.message || []).map(row => ({
                value: row.lot_no,
                label: row.lot_no + ' — ' + (row.container_count || 0) + ' container(s)',
            }));
            d.fields_dict.lot_no.df.options = lots;
            d.fields_dict.lot_no.refresh();
        },
    });

    // On lot change → load containers and render checkboxes.
    d.fields_dict.lot_no.df.onchange = function () {
        const lot_no = d.get_value('lot_no');
        if (!lot_no) return;
        frappe.call({
            method: 'mhr.utilis.get_hty_containers_for_lot',
            args: { lot_no: lot_no, company: frm.doc.company || null },
            callback: function (r) {
                mi1_i39_render_containers(d, r.message || []);
            },
        });
    };

    d.show();
    d._hty_state = { containers: [] };
}

function mi1_i39_render_containers(d, containers) {
    d._hty_state.containers = containers;
    if (!containers.length) {
        d.fields_dict.containers_html.$wrapper.html(
            '<div class="text-muted">' + __('No submitted Containers for this lot.') + '</div>'
        );
        return;
    }
    let html = '<div class="hty-container-list">';
    html += '<table class="table table-bordered"><thead><tr>';
    html += '<th style="width:30px;"><input type="checkbox" class="hty-pick-all"/></th>';
    html += '<th>' + __('Container') + '</th>';
    html += '<th>' + __('Container No') + '</th>';
    html += '<th>' + __('Item') + '</th>';
    html += '<th class="text-right">' + __('Batches') + '</th>';
    html += '<th class="text-right">' + __('Total Cone') + '</th>';
    html += '<th class="text-right">' + __('Net Weight') + '</th>';
    html += '<th>' + __('Date') + '</th>';
    html += '</tr></thead><tbody>';
    containers.forEach((c, idx) => {
        html += '<tr>';
        html += `<td><input type="checkbox" class="hty-pick" data-name="${frappe.utils.escape_html(c.container)}"/></td>`;
        html += `<td>${frappe.utils.escape_html(c.container)}</td>`;
        html += `<td>${frappe.utils.escape_html(c.container_no || '')}</td>`;
        html += `<td>${frappe.utils.escape_html(c.item_code || '')}</td>`;
        html += `<td class="text-right">${c.total_batches || 0}</td>`;
        html += `<td class="text-right">${c.total_cone || 0}</td>`;
        html += `<td class="text-right">${(c.total_net_weight || 0)}</td>`;
        html += `<td>${frappe.utils.escape_html((c.posting_date || '').toString())}</td>`;
        html += '</tr>';
    });
    html += '</tbody></table></div>';
    d.fields_dict.containers_html.$wrapper.html(html);

    // Wire the master-checkbox.
    d.fields_dict.containers_html.$wrapper.find('.hty-pick-all').on('change', function () {
        const checked = this.checked;
        d.fields_dict.containers_html.$wrapper.find('.hty-pick').prop('checked', checked);
    });
}

function mi1_i39_proceed(frm, d) {
    const $picks = d.fields_dict.containers_html.$wrapper.find('.hty-pick:checked');
    if (!$picks.length) {
        frappe.msgprint({
            title: __('Select at least one Container'),
            message: __('Step 3 requires multi-selecting Containers before Proceed.'),
            indicator: 'orange',
        });
        return;
    }
    const names = $picks.map((_, el) => $(el).data('name')).get();
    frappe.call({
        method: 'mhr.utilis.get_hty_batches_for_containers',
        args: { container_names: names },
        freeze: true,
        freeze_message: __('Loading batches…'),
        callback: function (r) {
            const rows = r.message || [];
            if (!rows.length) {
                frappe.msgprint(__('Selected Containers have no batch rows.'));
                return;
            }
            frm.clear_table('items');
            rows.forEach(row => {
                const child = frm.add_child('items', {
                    item_code: row.item_code,
                    qty: row.qty,
                    batch_no: row.batch_no,
                    warehouse: row.warehouse || frm.doc.set_warehouse,
                    custom_container_no: row.custom_container_no,
                    custom_lot_no: row.custom_lot_no,
                    custom_cone: row.custom_cone,
                    custom_sr_no: row.custom_sr_no,
                    custom_gross_weight: row.custom_gross_weight,
                    custom_supplier_batch_no: row.custom_supplier_batch_no,
                });
            });
            // MI1-I75 (Raj 2026-06-29): sort by Supplier Batch No ascending after fetch — HTY-only entry point.
            frm.doc.items.sort((a, b) =>
                String(a.custom_supplier_batch_no || '').localeCompare(
                    String(b.custom_supplier_batch_no || ''),
                    undefined, { numeric: true, sensitivity: 'base' }
                )
            );
            frm.doc.items.forEach((row, i) => { row.idx = i + 1; });
            frm.refresh_field('items');
            d.hide();
            frappe.show_alert({
                message: __('Added {0} batch row(s) from {1} container(s).', [rows.length, names.length]),
                indicator: 'green',
            });
        },
    });
}

frappe.ui.form.on('Delivery Note', {
