// MI1-I31 — auto-fetch the customer's primary Address Name + the
// short-text display when a Delivery Stop's customer is set or changes.
// Mirrors ERPNext's standard Customer → Address default lookup.

function mi1_i31_fetch_default_address(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row || !row.customer) return;
    if (row.address) return;  // user already chose one — don't clobber

    frappe.call({
        method: 'frappe.contacts.doctype.address.address.get_default_address',
        args: { name: row.customer, doctype: 'Customer' },
        callback: function (r) {
            const addr = r && r.message;
            if (!addr) return;
            frappe.model.set_value(cdt, cdn, 'address', addr);
            // Hydrate the display text via the helper Frappe uses on
            // standard address-text fields.
            frappe.call({
                method: 'frappe.contacts.doctype.address.address.get_address_display',
                args: { address_dict: addr },
                callback: function (rr) {
                    if (rr && rr.message) {
                        frappe.model.set_value(cdt, cdn, 'customer_address', rr.message);
                    }
                },
            });
        },
    });
}

frappe.ui.form.on('Delivery Stop', {
    customer: mi1_i31_fetch_default_address,
});
